import { useState } from "react";

function App() {
  const [file, setFile] = useState(null);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleUpload = async () => {
    if (!file) return alert("Please select an image");

    const formData = new FormData();
    formData.append("file", file);

    setLoading(true);
    setResult(null);

    try {
      const response = await fetch("http://127.0.0.1:8000/api/audit", {
        method: "POST",
        body: formData,
      });

      const data = await response.json();
      setResult(data);
    } catch (error) {
      console.error(error);
      alert("Something went wrong!");
    }

    setLoading(false);
  };

  return (
    <div style={styles.container}>
      <h1>🚗 ClaimPilot AI</h1>
      <p>Upload vehicle damage photo to generate AI repair estimate</p>

      <input
        type="file"
        accept="image/*"
        onChange={(e) => setFile(e.target.files[0])}
      />

      <button onClick={handleUpload} style={styles.button}>
        {loading ? "Analyzing..." : "Run AI Audit"}
      </button>

      {result && (
        <div style={styles.resultBox}>
          <h2>Audit Result</h2>

          <p><strong>Total Estimate:</strong> {result.total_estimate_pkr} PKR</p>
          <p><strong>Verdict:</strong> {result.verdict}</p>
          <p><strong>Fraud Analysis:</strong> {result.fraud_analysis}</p>
          <p><strong>Fraud Score:</strong> {result.fraud_confidence_score}</p>

          <h3>Damaged Parts</h3>
          <ul>
            {result.damaged_parts?.map((part, index) => (
              <li key={index}>{part}</li>
            ))}
          </ul>

          <h3>Itemized Costs</h3>
          <pre>{JSON.stringify(result.itemized_costs, null, 2)}</pre>
        </div>
      )}
    </div>
  );
}

const styles = {
  container: {
    textAlign: "center",
    padding: "40px",
    fontFamily: "Arial",
  },
  button: {
    marginTop: "20px",
    padding: "10px 20px",
    fontSize: "16px",
    cursor: "pointer",
  },
  resultBox: {
    marginTop: "30px",
    padding: "20px",
    border: "1px solid #ccc",
    borderRadius: "10px",
    textAlign: "left",
    display: "inline-block",
  },
};

export default App;
